CREATE TABLE IF NOT EXISTS `documents` (
  `collection_name` VARCHAR(255) NOT NULL,
  `doc_id` VARCHAR(255) NOT NULL,
  `data` LONGTEXT,
  `updated_at` BIGINT,
  PRIMARY KEY (`collection_name`, `doc_id`)
);
);

-- Data for table: users
