INSERT IGNORE INTO `config` (`id`, `homeStats`, `publicSectionsVisibility`, `footerInfo`, `boardMembers`, `loanProducts`, `testimonials`, `blogs`, `teamMembers`, `heroSlides`, `aboutPage`, `homePageContent`, `mission`, `vision`) VALUES ('settings', '{"customersReached_en":"250","loansFinanced_om":"","totalSavings_om":"","loansFinanced":"78","branchesOpened_en":"1","totalSavings":"8.0 M","customersReached":"250","branchesOpened_am":"","customersReached_om":"","customersReached_am":"","branchesOpened_om":"","branchesOpened":"1","totalSavings_en":"8.0 M","totalSavings_am":"","loansFinanced_am":"","loansFinanced_en":"78"}', '{"trust":true,"ctas":true,"aboutTestimonials":true,"blog":true,"aboutStructure":true,"whyChooseUs":true,"pageProducts":true,"pageContact":true,"aboutManagement":true,"pageFaq":true,"metrics":false,"testimonials":true,"hero":true,"aboutBoard":true}', '{"phone":"+251 911 000 000","address":"Addis Aratkilo Market Building, 4th Floor, Arat Kilo, Addis Ababa, Ethiopia","email":"support@amarach.com","socials":{"linkedin":"https://www.linkedin.com/company/amarachsacco/about/?viewAsMember=true","telegram":"https://t.me/+wZONHbQFUxk5NTk8","whatsapp":"","googlePlus":"","twitter":"https://twitter.com/amarach","facebook":"https://facebook.com/amarach","instagram":""}}', '[{"img":"","role":"Board Member","name":"Addis Abitew "},{"role":"Board Member","name":"Dereje Kefelegn","img":""},{"role":"Board Member","name":"Wondwose Birhanu","img":""},{"img":"","name":"Sirak Girma","role":"Board Member"},{"role":"Board Member","name":"Yitbarek Tilahun","img":""}]', '[{"surcharge":"2%","maxDuration":3,"description":"Medical bills, school fees, or urgent stock purchase.","interestRate":"10%","name":"Emergency / Flash Loan","image":"https://amarachsacco.com/static/banner.png","features":"Fast approval (24hrs); Personal guranter collateral (based on 4x savings)."},{"description":"Small business inventory or agricultural inputs.","surcharge":"2%","maxDuration":6,"image":"https://amarachsacco.com/static/wcap.png","features":"Repayment: Monthly installments; Requires member guarantor.(based on 4x savings).","interestRate":"15%","name":"Working Capital Loan"},{"maxDuration":9,"surcharge":"2%","description":"Holiday expenses or seasonal business cycles.","interestRate":"15%","name":"Festive / Seasonal Loan","image":"https://wpblogassets.paytm.com/paytmblog/uploads/2023/09/Blog_Paytm_Personal-loan-repayment-strategies-800x500.jpg","features":"Tailored for peak seasons (e.g., Holidays/Harvest); Flexible grace period.Requires member guarantor.(based on 4x savings)."},{"name":"Personal / Consumer Loan","interestRate":"17% - 20%","features":"Requires collateral and or  2 member guarantors; Monthly Amortization.","image":"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQCmeqPTRZkSDQTQhob2ep1kXqpacYQyjRJkg&s","maxDuration":12,"surcharge":"3%","description":"Electronic goods, furniture, or minor home repairs."},{"maxDuration":60,"surcharge":"3%","description":"Real estate, vehicle purchase, or large business expansion.","interestRate":"17% - 20%","name":"Asset / Investment Loan","image":"https://wpblogassets.paytm.com/paytmblog/uploads/2023/09/Blog_Paytm_Personal-loan-repayment-strategies-800x500.jpg","features":"Collateral Required; Longer grace period (3-6 months); Tiered repayment."}]', '[]', '[{"excerpt":"blog_excerpt_1","authorName":"Yohannes","id":"1","authorEmail":"hirasoftwareaddis@gmail.com","title":"Saving money","content":"\nSaving money doesn''t have to be painful. By following these five simple steps, you can build a robust financial cushion for your future.\n\n### 1. Track Your Spending\nYou can''t save what you don''t measure. Use our digital dashboard to categorize your expenses and identify where your money is going.\n\n### 2. Automate Your Savings\nSet up a recurring transfer to your Amarach savings account. Even a small amount every week adds up significantly over time.\n\n### 3. The 50/30/20 Rule\nAllocate 50% of your income to needs, 30% to wants, and 20% to savings and debt repayment.\n\n### 4. Reduce High-Interest Debt\nPrioritize paying off credit cards or informal loans. Our Business Growth loans offer much better rates to help you consolidate.\n\n### 5. Review and Adjust\nFinancial planning is a journey. Review your progress monthly and adjust your goals as your income or needs change.\n    ","category":"cat_financial_literacy","image":"https://picsum.photos/seed/blog0/800/600","media":[{"caption":"","type":"video","url":"https://youtu.be/ms1nTeFO7ps?si=5PNA0yc-zaz09Dub"},{"type":"video","caption":" Warren Buffett: Why EVERYTHING Changes After $20,000.","url":"https://youtu.be/UH48X2vAAtU?si=yB7mmvKVrvcsNo2U"}],"date":"Oct 12, 2023"},{"media":[{"caption":"","type":"video","url":"https://youtu.be/RFxZxuKgiYg?si=roEU1tIi3lPKckpN"}],"image":"https://picsum.photos/seed/blog1/800/600","date":"Oct 10, 2023","content":"\n\n### New Subsection\n\n\n\nJoining a Savings and Credit Cooperative (SACCO) like Amarach is more than just opening a bank account; it''s joining a community of like-minded individuals working towards mutual prosperity.\n\n### Why Choose a SACCO?\nUnlike traditional banks, SACCOs are owned by their members. This means our primary goal is your financial well-being, not corporate profit.\n\n### Key Benefits:\n* **Higher Interest on Savings:** We return our surplus to members through better rates.\n* **Lower Loan Rates:** Access affordable credit for business or personal needs.\n* **Community Support:** Benefit from financial literacy workshops and peer support.\n* **Democratic Control:** Every member has a voice in how the SACCO is run.\n\nWhether you''re a small business owner or a student, Amarach SACCO provides the tools you need to grow.\n    ","category":"cat_community","title":"Joining a Savings and Credit Cooperative","references":[{"title":"video","url":"https://www.youtube.com/results?search_query=financial+sacco"}],"excerpt":"oining a Savings and Credit Cooperative (SACCO) like Amarach is more than just opening a bank account;","id":"2"},{"id":"3","date":"Oct 05, 2023","image":"https://picsum.photos/seed/blog2/800/600","excerpt":"blog_excerpt_3","content":"\nRetirement might seem far away, but the best time to start planning was yesterday. The second best time is today.\n\n### The Power of Compound Interest\nThe earlier you start, the more time your money has to grow. Even small, consistent contributions can grow into a significant nest egg over decades.\n\n### Our Retirement Solutions:\n1. **Fixed Deposit Accounts:** Lock in high interest rates for long-term growth.\n2. **Voluntary Savings:** Flexible contributions that you can increase as your income grows.\n3. **Financial Counseling:** Our experts can help you calculate how much you need to save to maintain your lifestyle.\n\nDon''t leave your future to chance. Start your retirement fund with Amarach SACCO today.\n    ","category":"cat_planning","title":"blog_title_3"},{"date":"Apr 23, 2026","id":"1776941275086","media":[],"image":"https://thumbs.dreamstime.com/b/income-increase-concept-upward-pile-money-income-increase-concept-upward-pile-coins-101863141.jpg","excerpt":"","title":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!  ","category":"ችግሩ የደመወዛችን/ገቢያችን ማነስ አይደለም!","content":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!\n\nብዙዎቻችን የገንዘብ ችግራችን የሚቀረፈው ደመወዛችን ሲጨምር ወይም ተጨማሪ ገቢ ስናገኝ ብቻ ይመስለናል። ነገር ግን እውነታው ከዚህ ይለያል፤ ገቢ እንደ አንድ \"መሳሪያ\" ነው፤ የገንዘብ ፍሰትን በአግባቡ ማስተዳደር ግን \"ጥበብ\" ነው።\nበየዓመቱ አነስተኛ ገቢ እያገኙ፣ ነገር ግን ከፍተኛ ገቢ ካላቸው ሰዎች የተሻለ የተጣራ ሀብት (Net Worth) ያላቸውን ሰዎች እናስተውላለን። ይህ እንዴት ሊሆን ቻለ?\nለገንዘብ እጥረት ቁጥር 1 ምክንያት፡ የኑሮ ዘይቤ ጣሪያ መልቀቅ (Lifestyle Creep)\nገቢያችን ሲጨምር አብሮ ወጪያችን መጨምሩን \"Lifestyle Creep\" እንለዋለን። ገቢ ሲጨምር መኪናው ይቀየራል፣ ቤቱ ይተለቃል፣ ወጪዎችም አብረው ይበዛሉ። በእንዲህ አይነት ሁኔታ ውስጥ ያሉ ሰዎች ሀብት እየገነቡ ሳይሆን፣ ይበልጥ ውድ ለሆነ የኑሮ \"መሮጫ ማሽን\" ነዳጅ እየገዙ ነው።\n\nየሀብት እውነተኛ ትርጉም\n\nሀብት ማለት ለሰዎች ለማሳየት የምታወጣው ገንዘብ ሳይሆን፣ በእጅህ አስቀርተህ ለስራ የምታውለው የገቢህ ክፍል ነው። ዛሬ በእጅህ ያለችውን 1,000 ብር ማስተዳደር ካልቻልክ፣ ነገ የምትመኘውን 1,000,000 ብር መቼም ቢሆን ልታስተዳድረው አትችልም።\n\nየገንዘብ ፍሰትዎን ለመቆጣጠር የሚረዱ ምክሮች፦\n\n1.በSACCO በኩል መቆጠብን ልማድ ያድርጉ፦ ገቢዎ ገና እጅዎ ሳይገባ የተወሰነውን ክፍል ለቁጠባ እንዲቀነስ ማድረግ የኑሮ ዘይቤዎ ከገቢዎ ጋር አብሮ እንዳያብጥ ይረዳል።\n2.\tበፍላጎት እና በአስፈላጊ ነገሮች መካከል ያለውን ልዩነት ይለዩ፦ አዲስ ገቢ ሲያገኙ ወዲያውኑ አዳዲስ ዕቃዎችን ከመግዛት ይቆጠቡ።\n3.\tየወጪ እቅድ (Budget) ይኑርዎት፦ ገንዘብዎ የት እንደሚሄድ ካልተቆጣጠሩት፣ ገንዘብዎ እርስዎን መቆጣጠር ይጀምራል።\n\nውድ የብድር እና ቁጠባ ማህበራችን አባላት፤\n\nሀብታም መሆን የሚጀምረው ከገቢ መጠን ሳይሆን ከገንዘብ አያያዝ ስነ-ልቦና ነው። ዛሬ የምትቆጥቧት እያንዳንዷ ሳንቲም የነገው የገንዘብ ነፃነታችሁ መሰረት ናት።\nእናንተስ የገንዘብ ፍሰታችሁን ለመቆጣጠር ምን እያደረጋችሁ ነው?  ከታች ባለው ሊነክ ይቀላቀሉን\n"},{"content":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!\nብዙዎቻችን የገንዘብ ችግራችን የሚቀረፈው ደመወዛችን ሲጨምር ወይም ተጨማሪ ገቢ ስናገኝ ብቻ ይመስለናል። ነገር ግን እውነታው ከዚህ ይለያል፤ ገቢ እንደ አንድ \"መሳሪያ\" ነው፤ የገንዘብ ፍሰትን በአግባቡ ማስተዳደር ግን \"ጥበብ\" ነው።\nበየዓመቱ አነስተኛ ገቢ እያገኙ፣ ነገር ግን ከፍተኛ ገቢ ካላቸው ሰዎች የተሻለ የተጣራ ሀብት (Net Worth) ያላቸውን ሰዎች እናስተውላለን። ይህ እንዴት ሊሆን ቻለ?\nለገንዘብ እጥረት ቁጥር 1 ምክንያት፡ የኑሮ ዘይቤ ጣሪያ መልቀቅ (Lifestyle Creep)\nገቢያችን ሲጨምር አብሮ ወጪያችን መጨምሩን \"Lifestyle Creep\" እንለዋለን። ገቢ ሲጨምር መኪናው ይቀየራል፣ ቤቱ ይተለቃል፣ ወጪዎችም አብረው ይበዛሉ። በእንዲህ አይነት ሁኔታ ውስጥ ያሉ ሰዎች ሀብት እየገነቡ ሳይሆን፣ ይበልጥ ውድ ለሆነ የኑሮ \"መሮጫ ማሽን\" ነዳጅ እየገዙ ነው።\nየሀብት እውነተኛ ትርጉም\nሀብት ማለት ለሰዎች ለማሳየት የምታወጣው ገንዘብ ሳይሆን፣ በእጅህ አስቀርተህ ለስራ የምታውለው የገቢህ ክፍል ነው። ዛሬ በእጅህ ያለችውን 1,000 ብር ማስተዳደር ካልቻልክ፣ ነገ የምትመኘውን 1,000,000 ብር መቼም ቢሆን ልታስተዳድረው አትችልም።\nየገንዘብ ፍሰትዎን ለመቆጣጠር የሚረዱ ምክሮች፦\n1.\tበSACCO በኩል መቆጠብን ልማድ ያድርጉ፦ ገቢዎ ገና እጅዎ ሳይገባ የተወሰነውን ክፍል ለቁጠባ እንዲቀነስ ማድረግ የኑሮ ዘይቤዎ ከገቢዎ ጋር አብሮ እንዳያብጥ ይረዳል።\n2.\tበፍላጎት እና በአስፈላጊ ነገሮች መካከል ያለውን ልዩነት ይለዩ፦ አዲስ ገቢ ሲያገኙ ወዲያውኑ አዳዲስ ዕቃዎችን ከመግዛት ይቆጠቡ።\n3.\tየወጪ እቅድ (Budget) ይኑርዎት፦ ገንዘብዎ የት እንደሚሄድ ካልተቆጣጠሩት፣ ገንዘብዎ እርስዎን መቆጣጠር ይጀምራል።\nውድ የብድር እና ቁጠባ ማህበራችን አባላት፤\nሀብታም መሆን የሚጀምረው ከገቢ መጠን ሳይሆን ከገንዘብ አያያዝ ስነ-ልቦና ነው። ዛሬ የምትቆጥቧት እያንዳንዷ ሳንቲም የነገው የገንዘብ ነፃነታችሁ መሰረት ናት።\nእናንተስ የገንዘብ ፍሰታችሁን ለመቆጣጠር ምን እያደረጋችሁ ነው?  ከታች ባለው ሊነክ ይቀላቀሉን\n","category":"Social","title":"Saving And Investment ","excerpt":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!\nብዙዎቻችን የገንዘብ ችግራችን የሚቀረፈው ደመወዛችን ሲጨምር ወይም ተጨማሪ ገቢ ስናገኝ ብቻ ይመስለናል። ነገር ግን እውነታው ከዚህ ይለያል፤ ገቢ እንደ አንድ \"መሳሪያ\" ነው፤ የገንዘብ ፍሰትን በአግባቡ ማስተዳደር ግን \"ጥበብ\" ነው።","image":"https://thumbs.dreamstime.com/b/income-increase-concept-upward-pile-money-income-increase-concept-upward-pile-coins-101863141.jpg","date":"Apr 23, 2026","id":"1776942455099"},{"authorEmail":"hirasoftwareaddis@gmail.com","id":"1776942741103","authorName":"Yohannes Mitike","excerpt":"","titleAm":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!","date":"Apr 23, 2026","media":[{"caption":"","type":"image","url":"https://thumbs.dreamstime.com/b/income-increase-concept-upward-pile-money-income-increase-concept-upward-pile-coins-101863141.jpg"}],"image":"https://thumbs.dreamstime.com/b/income-increase-concept-upward-pile-money-income-increase-concept-upward-pile-coins-101863141.jpg","category":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!","content":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!\nብዙዎቻችን የገንዘብ ችግራችን የሚቀረፈው ደመወዛችን ሲጨምር ወይም ተጨማሪ ገቢ ስናገኝ ብቻ ይመስለናል። ነገር ግን እውነታው ከዚህ ይለያል፤ ገቢ እንደ አንድ \"መሳሪያ\" ነው፤ የገንዘብ ፍሰትን በአግባቡ ማስተዳደር ግን \"ጥበብ\" ነው።\nበየዓመቱ አነስተኛ ገቢ እያገኙ፣ ነገር ግን ከፍተኛ ገቢ ካላቸው ሰዎች የተሻለ የተጣራ ሀብት (Net Worth) ያላቸውን ሰዎች እናስተውላለን። ይህ እንዴት ሊሆን ቻለ?\nለገንዘብ እጥረት ቁጥር 1 ምክንያት፡ የኑሮ ዘይቤ ጣሪያ መልቀቅ (Lifestyle Creep)\nገቢያችን ሲጨምር አብሮ ወጪያችን መጨምሩን \"Lifestyle Creep\" እንለዋለን። ገቢ ሲጨምር መኪናው ይቀየራል፣ ቤቱ ይተለቃል፣ ወጪዎችም አብረው ይበዛሉ። በእንዲህ አይነት ሁኔታ ውስጥ ያሉ ሰዎች ሀብት እየገነቡ ሳይሆን፣ ይበልጥ ውድ ለሆነ የኑሮ \"መሮጫ ማሽን\" ነዳጅ እየገዙ ነው።\nየሀብት እውነተኛ ትርጉም\nሀብት ማለት ለሰዎች ለማሳየት የምታወጣው ገንዘብ ሳይሆን፣ በእጅህ አስቀርተህ ለስራ የምታውለው የገቢህ ክፍል ነው። ዛሬ በእጅህ ያለችውን 1,000 ብር ማስተዳደር ካልቻልክ፣ ነገ የምትመኘውን 1,000,000 ብር መቼም ቢሆን ልታስተዳድረው አትችልም።\nየገንዘብ ፍሰትዎን ለመቆጣጠር የሚረዱ ምክሮች፦\n1.\tበSACCO በኩል መቆጠብን ልማድ ያድርጉ፦ ገቢዎ ገና እጅዎ ሳይገባ የተወሰነውን ክፍል ለቁጠባ እንዲቀነስ ማድረግ የኑሮ ዘይቤዎ ከገቢዎ ጋር አብሮ እንዳያብጥ ይረዳል።\n2.\tበፍላጎት እና በአስፈላጊ ነገሮች መካከል ያለውን ልዩነት ይለዩ፦ አዲስ ገቢ ሲያገኙ ወዲያውኑ አዳዲስ ዕቃዎችን ከመግዛት ይቆጠቡ።\n3.\tየወጪ እቅድ (Budget) ይኑርዎት፦ ገንዘብዎ የት እንደሚሄድ ካልተቆጣጠሩት፣ ገንዘብዎ እርስዎን መቆጣጠር ይጀምራል።\nውድ የብድር እና ቁጠባ ማህበራችን አባላት፤\nሀብታም መሆን የሚጀምረው ከገቢ መጠን ሳይሆን ከገንዘብ አያያዝ ስነ-ልቦና ነው። ዛሬ የምትቆጥቧት እያንዳንዷ ሳንቲም የነገው የገንዘብ ነፃነታችሁ መሰረት ናት።\nእናንተስ የገንዘብ ፍሰታችሁን ለመቆጣጠር ምን እያደረጋችሁ ነው?  ከታች ባለው ሊነክ ይቀላቀሉን\nhttps://t.me/amarachsacco","title":"የገንዘብ ችግርህ መፍትሄ የገቢ መጨመር ብቻ አይደለም!"},{"authorImage":"https://lh3.googleusercontent.com/a/ACg8ocJQ2vVw8hEj6HosHB7sf8i1kfaGFMGhYHWz7SsFZtJx0ts0ZA=s96-c","id":"1777367178961","authorEmail":"tosirac@gmail.com","excerpt":"“Do I really need this?” is a simple question, yet it has the power to transform our financial lives. “ይህን ነገር በእርግጥ ያስፈልገኛል?” የሚለው ጥያቄ ቀላል ቢመስልም የገንዘብ ሕይወታችንን ሊቀይር የሚችል ነው። ","authorName":"Sirak Girmma","category":"Financial Literacy","content":"**“Do I really need this?”** is a simple question, yet it has the power to transform our financial lives. As Dave Ramsey wisely said, “We buy things we don’t need with money we don’t have to impress people we don’t like.” This reflects a common challenge many people face today—confusing wants with needs. Needs are the basics we cannot live without, while wants are often driven by emotion, habit, or social pressure. Unfortunately, saving culture is still developing, and many households spend most of their income without planning for the future. \nThe good news is that building a saving habit does not depend on how much you earn, but on how you manage what you have. Starting small—saving a little from each income—can create a strong financial foundation over time. By focusing on needs, reducing unnecessary wants, and making saving a regular habit, individuals can improve their financial stability and prepare for future opportunities. Asking “Do I really need this?” before every expense is not just a question—it is a mindset that leads to discipline, better choices, and long-term financial growth.\n\n**“ይህን ነገር በእርግጥ ያስፈልገኛል?”**\n“ይህን ነገር በእርግጥ ያስፈልገኛል?” የሚለው ጥያቄ ቀላል ቢመስልም የገንዘብ ሕይወታችንን ሊቀይር የሚችል ነው። የፋይናንስ ባለሙያው  Dave Ramsey እንደሚለው፣ “የምንፈልጋቸው ነገሮች ለመግዛት ያላቀድነውን ገንዘብ እናወጣለን፤ ይህ እውነታ ብዙዎቻችን ለፍላጎታችን የማድላታችንን ችግር ያሳያል፡፡ ፍላጎት (want)ን ከአስፈላጊ (need) ጋር መቀላቀል። አስፈላጊዎች የሕይወታችን መሠረታዊ ፍላጎቶች ሲሆኑ፣ ፍላጎቶች ግን ብዙ ጊዜ ከስሜት ወይም ከልምድ የሚመጡ ናቸው። ይህን ልዩነት መረዳት እጅግ አስፈላጊ ነው። ብዙዎች ሙሉ ገቢያቸውን ለአስፈላጊና ለፍላጎቶቻቸው ይጠቀማሉ፡፡ የቁጠባ ልምድ የላቸውም፡፡ \nመልካም ዜናው ግን የቁጠባ ልምድ ለመጀመር ትልቅ ገቢ አያስፈልግም፡፡ በትንሽ እና ቀጣይነት ባለው እርምጃ ይጀምራል። ከገቢ ትንሽ ብቻ በመቆጠብ እንኳን በጊዜ ሂደት ትልቅ ውጤት ማምጣት ይቻላል። በአስፈላጊ ነገሮች ላይ ማተኮር፣ ፍላጎቶችን መቀነስ እና ቁጠባን እንደ ቀዳሚ ልምድ መውሰድ የገንዘብ ደህንነትን ያሻሽላል። \nከዚህ በኋላ እያንዳንዱን ወጪ ከማድረግዎ በፊት “ይህን ነገር በእርግጥ ያስፈልገኛል?” ብለው መጠየቅ ይጀምሩ፡፡ ይህ ጥያቄዎ የሕይወት መንገድ ይሆናል፤  ወደ ተሻለ ውሳኔ፣ ወደ ትክክለኛ ቁጠባ እና ወደ የወደፊት እድገት ይመራል።\n","title":"“Do I really need this?”","date":"Apr 28, 2026","titleAm":"“ይህን ነገር በእርግጥ ያስፈልገኛል?”","authorId":"7HGoVvURf0Sh4n0i82sfI3Ra0BP2","image":"https://amarachsacco.com/static/blog/yet.png"},{"date":"May 25, 2026","media":[{"type":"video","caption":"Money Market Fund","url":"https://www.youtube.com/watch?v=NKg-eqGCgzk"}],"authorEmail":"jonmersha@gmail.com","titleAm":"💰 የገንዘብ ገበያ ፈንድ (Money Market Fund) ምንድን ነው? ከባንክ ቁጠባስ በምን ይለያል?","authorId":"t4kdrCrtQxcPqoIFKTRQU3ps7jh1","image":"https://amarachsacco.com/static/blog/fund.png","title":"💰 የገንዘብ ገበያ ፈንድ (Money Market Fund) ምንድን ነው? ከባንክ ቁጠባስ በምን ይለያል?","category":"Financial Literacy","content":"ብዙዎቻችን ገንዘባችንን ባንክ ማስቀመጥ ብቸኛውና አስተማማኙ መንገድ ይመስለናል። ነገር ግን በፋይናንስ ሥርዓቱ ውስጥ ከባንክ የተሻለ ወለድ የሚያስገኝ እና ይበልጥ ደኅንነቱ የተጠበቀ የገንዘብ ገበያ ፈንድ (Money Market Fund - MMF) የተባለ አማራጭ እንዳለ ያውቃሉ?\nየናቦ ካፒታል (Nabo Capital) ዋና ሥራ አስፈጻሚ ፒየስ ሙቺሪ (Pius Muchiri) በቅርቡ በሰጡት ማብራሪያ መሠረት፣ በባንክ እና በ MMF መካከል ያሉትን መሠረታዊ ልዩነቶችና ጥቅሞች በዚህ ጽሑፍ በዝርዝር እንመለከታለን።\n\n## 🔍 1. የፋይናንስ ተቋማትን ዓላማ ጠንቅቆ ማወቅ\nሰዎች ወደ ፋይናንስ ተቋማት ሲመጡ ብዙውን ጊዜ የተቋማቱን መሠረታዊ ልዩነት አይረዱም። እያንዳንዱ ተቋም የተፈጠረበት የራሱ ዓላማ አለው፦\n•\tባንኮች (Banks)፦ የተቋቋሙት ለግብይት ማመቻቻ (Transactions) ብቻ ነው። የትምህርት ቤት ክፍያ መክፈል፣ ዕቃ መግዛት እና የእለት ተእለት የገንዘብ ዝውውሮችን ለማድረግ ያገለግላሉ። ስለዚህ ባንክ ውስጥ መቀመጥ ያለበት የክፍያ ገንዘብ ብቻ መሆን አለበት።\n•\tየቁጠባና ብድር ማህበራት (SACCOs)፦ የተፈጠሩት አባላት እርስ በእርስ ዋስ በመሆን በጋራ እንዲበደሩ ለማገዝ ነው። ከእነዚህ ተቋማት ካልተበደሩ በስተቀር ኢንቨስት ለማድረግ ምርጥ አማራጭ አይደሉም።\n•\tየኢንቨስትመንት ኩባንያዎች (MMF)፦ ገንዘብን ለማውለድ፣ ለማሳደግ እና ኢንቨስት ለማድረግ የተፈጠሩ ትክክለኛ ቦታዎች ናቸው።\n## ⚖️ 2. በባንክ እና በገንዘብ ገበያ ፈንድ (MMF) መካከል ያሉ 4 ዋና ልዩነቶች\nየገንዘብ ገበያ ፈንድ (MMF) ከባንክ አካውንት የሚለይባቸው ዋና ዋና ነጥቦች የሚከተሉት ናቸው፦\nሀ. የገንዘቡ ባለቤትነት ማነው?\nገንዘብን ባንክ ውስጥ ሲያስቀምጡ ገንዘቡ የባንኩ ንብረት ይሆናል (በባንኩ የሒሳብ መግለጫ ላይ እንደ እዳ ነው የሚመዘገበው)። ነገር ግን በ MMF ውስጥ ሲያስቀምጡ ገንዘቡ በተለየ የጥበቃ አካውንት (Custody Account) ውስጥ ስለሚቀመጥ ሁልጊዜም የእርስዎ ንብረት ሆኖ ይቆያል።\nለ. የወለድ መጠን (Returns)\nባንኮች በጣም ዝቅተኛ ወለድ የሚሰጡ ሲሆን፣ ለማሻሻልም ድርድር ይጠይቃሉ። በ MMF ውስጥ ግን ምንም ዓይነት ድርድር ሳያስፈልግ፣ ገንዘብዎ ከባንክ እጅግ የላቀ እና በገበያው ውስጥ ያለውን ከፍተኛውን የወለድ ጥቅም በቀጥታ በየቀኑ እንዲያገኝ ይደረጋል።\nሐ. ደኅንነት እና የኪሳራ ስጋት\nአንድ ባንክ ቢከስር ከተቀማጭ ገንዘብዎ ውስጥ በጣም ውስን የሆነውን ክፍል ብቻ በሕግ ያገኛሉ (የቀረው ሊጠፋ ይችላል)። ነገር ግን የፈንድ ማናጀር ኩባንያው ቢከስር እንኳ፣ የእርስዎ ገንዘብ በተለየ ጥበቃ ስር ስላለ አይነካም፤ የመንግሥት ተቆጣጣሪ አካል ሌላ ማናጀር በመመደብ የኢንቨስትመንት ጉዞዎ እንዲቀጥል ያደርጋል።\nመ. ገንዘብን የማውጣት ፍጥነት (Liquidity)\nበባንክ ውስጥ የተወሰነ ጊዜ የተቀመጠ ገንዘብን (Fixed Deposit) ጊዜው ሳይደርስ ቀድመው ካወጡ ወለድ ያጣሉ (ቅጣት አለው)። በ MMF ውስጥ ግን የቆየበትን ጊዜ ወለድ ሳያጡ ገንዘቡን በማንኛውም ጊዜ ማውጣት ይቻላል። ሆኖም ገንዘቡ በእጅዎ ለመግባት እስከ 48 ሰዓታት ሊፈጅ ይችላል።\n💡 የብሎጉ ማስታወሻ፦ ይህ የ48 ሰዓት መዘግየት ሆን ተብሎ የተደረገ ስልት ነው! ሰዎች በስሜት ተገፋፍተው ወይም ለጊዜያዊ ፈገግታ (ለምሳሌ ቅዳሜና እሁድ ለመዝናናት) የኢንቨስትመንት ገንዘባቸውን በቀላሉ እንዳያባክኑት ይከላከላል።\n## 🛡️ 3. የገንዘብ ገበያ ፈንድ (MMF) እንዴት ደኅንነቱን ይጠብቃል?\nበ MMF ውስጥ የእርስዎን ገንዘብ ከአደጋ ለመጠበቅ አራት የመከላከያ እርከኖች አሉ። በዚህም ምክንያት MMF ከባንክ አካውንት ይበልጥ ደኅንነቱ የተጠበቀ ነው ተብሎ ይታመናል፦\n1.\tየአካውንት መለያየት (Custody)፦ የእርስዎ ገንዘብ ፈንዱን ከሚያስተዳድረው ኩባንያ ሀብት ጋር በፍጹም አይቀላቀልም።\n2.\tየኢንቨስትመንት ስርጭት (Diversification)፦ ሕጉ ማናጀሩ ሁሉንም ገንዘብ በአንድ ቦታ እንዳያስቀምጥ ይከለክላል (ቢበዛ 25% ብቻ በአንድ ተቋም)። ስለዚህ አንዱ ቦታ ችግር ቢኖር እንኳ ቀሪው 75% አስተማማኝ ሆኖ ይቆያል።\n3.\tባለአደራ ተቋማት (Trustees)፦ ትልልቅ ባንኮች (ለምሳሌ KCB Trustee) የፈንድ ማናጀሩ የገባውን ቃል እና ሕጉን ማክበሩን በየሩብ ዓመቱ ይቆጣጠራሉ።\n## 4.\tየካፒታል ማርኬት ባለሥልጣን (CMA)፦ የመንግሥት ተቆጣጣሪ አካል ጥብቅ ኦዲትና ቁጥጥር ያደርጋል።\n📝 ማጠቃለያ፦ የእርስዎ ቀጣይ እርምጃ ምን መሆን አለበት?\nባንክ አካውንት ካለዎት፣ ጎን ለጎን የገንዘብ ገበያ ፈንድ (MMF) አካውንት ሊኖርዎት ይገባል። ደሞዝዎ ወይም ማንኛውም ገቢዎ ባንክ ሲገባ፣ መጀመሪያ ራስዎን ይክፈሉ — የሚቆጥቡትን ገንዘብ በቀጥታ ወደ MMF በማዛወር ከዛሬውኑ ገንዘብዎ ገንዘብ እንዲወልድ ያድርጉ!\n💬 እርስዎስ? ገንዘብዎን የሚያስቀምጡት የት ነው? ስለ MMF ያላችሁን አስተያየት ወይም ጥያቄ ከታች ባለው የኮሜንት ሳጥን ውስጥ ያጋሩን!\n","id":"1779684972552","excerpt":"ገንዘብዎ ባንክ ውስጥ ዝም ብሎ ተቀምጧል? ብዙዎቻችን ቁጠባችንን ባንክ ማድረጉ አስተማማኝ ይመስለናል። ነገር ግን በፋይናንስ ሥርዓቱ ውስጥ ከባንክ የተሻለ ወለድ የሚያስገኝ እና እጅግ የላቀ የደኅንነት ዋስትና ያለው አማራጭ አለ፤ እሱም የገንዘብ ገበያ ፈንድ (Money Market Fund - MMF) ይባላል።\n\nይህ የብሎግ ጽሑፍ የናቦ ካፒታል (Nabo Capital) ዋና ሥራ አስፈጻሚ ፒየስ ሙቺሪ (Pius Muchiri) የሰጡትን ወርቃማ ማብራሪያ መሠረት በማድረግ፤ ባንክ ለምን ለግብይት ብቻ መዋል እንዳለበት፣ በ MMF ውስጥ ያሉትን 4 የመከላከያ እርከኖች እና ገንዘብዎን ሳያባክኑ ለነገ የሚሆን ሀብት እንዴት ማፍራት እንደሚችሉ በግልጽ ያሳየዎታል። ያንብቡ፣ ይማሩ፣ የገንዘብ አጠቃቀምዎን ዛሬውኑ ይቀይሩ!","authorName":"Yohannes Mitike Mersha","authorImage":"https://lh3.googleusercontent.com/a/ACg8ocLwwccRWoBikZJ7olJjdfNJb4GAcEfjQn-DAgpIVlVkuyLc-IMh=s96-c"},{"authorEmail":"jonmersha@gmail.com","date":"May 25, 2026","media":[{"type":"video","caption":"🪙 የገንዘብ ዕውቀት ለልጆች","url":"https://www.youtube.com/watch?v=0iRbD5rM5qc"}],"authorImage":"https://lh3.googleusercontent.com/a/ACg8ocLwwccRWoBikZJ7olJjdfNJb4GAcEfjQn-DAgpIVlVkuyLc-IMh=s96-c","id":"1779701182205","excerpt":"ልጅዎ የገንዘብ አጠቃቀምን ገና ከልጅነቱ እንዲማር ይፈልጋሉ? ይህ አጭር መመሪያ፣ ልጆች የነገውን ሕይወታቸውን በስኬት እንዲመሩ የሚያግዙ መሠረታዊ የገንዘብ ዕውቀቶችን (Financial Literacy) በቀላል ቋንቋ ያስተምራል። በቪዲዮው ላይ የተብራሩትን እንደ ፍላጎት እና አስፈላጊነት መለየት፣ በጀት ማውጣት፣ እንዲሁም በቁጠባ እና በብድር መካከል ያሉትን ልዩነቶች በማወቅ ለልጆችዎ ጠንካራ የፋይናንስ መሠረት ዛሬውኑ ያስይዙ!","authorName":"Amarach Team","title":"🪙 የገንዘብ ዕውቀት ለልጆች፦ መሠረታዊ የፋይናንስ እና የበጀት አያያዝ መመሪያ","content":"## 📘 1. መሠረታዊ ፍላጎቶች (Needs) እና ምኞቶች (Wants)፦ የትኛው ይቀድማል?\nለልጆች ማስተማር ያለብን የመጀመሪያው እና ትልቁ ነገር በነዚህ ሁለት ቃላት መካከል ያለውን ልዩነት ነው፦\n\n- መሠረታዊ ፍላጎቶች (Needs) — \"የግድ የሚያስፈልጉኝ\"፦ አንድ ሰው በሕይወት ለመኖር እና ጤናማ ለመሆን የግድ የሚያስፈልጉት ነገሮች ናቸው። ለምሳሌ፦ ምግብ፣ ውኃ፣ ንጹሕ ልብስ እና መጠለያ (ቤት)። እነዚህ ነገሮች ከሌሉ መኖር አንችልም።\n- ምኞቶች (Wants) — \"ቢኖሩ ደስ የሚሉኝ\"፦ ቢኖሩ ደስ የሚሉ፣ ጨዋታን የሚያደምቁ ነገር ግን ባይኖሩ እንኳ መኖር የምንችልባቸው ነገሮች ናቸው። ለምሳሌ፦ የቪዲዮ ጌሞች፣ አዲስ አሻንጉሊት፣ ስኬትቦርድ ወይም አይስክሬም።\n\n💡 ለልጆች የሚሆን ምክር፦ መደብር ውስጥ አንድ ነገር አይተን ከመግዛታችን በፊት \"ይህ ነገር በሕይወት ለመኖር የግድ ያስፈልገኛል (Need) ወይስ ዝም ብዬ ተመኝቼው ነው (Want)?\" ብለን ራሳችንን መጠየቅ ትልቅ የብልህነት መጀመሪያ ነው!\n\n## 📊 2. በጀት (Budget) ማውጣት፦ የኪስ ገንዘባችንን መቆጣጠሪያ ካርታ\nበጀት ማለት ማግኘት የምንችለውን እና ማውጣት የምንፈልገውን ገንዘብ አስቀድመን የምናቅድበት የኪስ ገንዘባችን መቆጣጠሪያ ካርታ ነው! ይህ ዕቅድ በሁለት ዋና ዋና መንገዶች ላይ ይቆማል፦\n\n- ገቢ (Income) — \"ወደ እኔ የሚመጣ\"፦ ወላጆቻችን በጥሩ ሥራችን ምክንያት የሚሰጡን የኪስ ገንዘብ (Allowance) ወይም በልደት ቀናችን ከዘመድ የምናገኘው የስጦታ ገንዘብ።\n\n- ወጪ (Expenses) — \"ከእኔ የሚወጣ\"፦ ለትምህርት ቤት ምሳ፣ ለደብተር ወይም ለምንፈልገው አሻንጉሊት የምንከፍለው ገንዘብ።\n\n💡 ለልጆች የሚሆን ምክር፦ በጀት ማውጣት ካለን አቅም በላይ እንዳናጠፋ እና የሌለንን ገንዘብ ከሰው ተበድረን ዕዳ (Debt) ውስጥ እንዳንገባ ይጠብቀናል። ሁልጊዜም ከምናገኘው በላይ ላለማውጣት ማቀድ አለብን!\n\n## 🐷 3. ቁጠባ (Saving) እና ብድር (Borrowing)፦ የነገው ስኬት\n- ቁጠባ (Saving) — \"ለነገ ማስቀመጥ\"፦ ያገኘነውን ገንዘብ በሙሉ ዛሬውኑ ሳናጠፋ፣ ለወደፊት ትልቅ ዓላማ ወይም ለድንገተኛ ነገር አስልተን በቁጠባ ሳጥናችን (Piggy Bank) ወይም ባንክ ውስጥ ማስቀመጥ ማለት ነው።\n\n- ብድር (Borrowing/Loan) — \"ከሰው መዋስ\"፦ አሁን በእጃችን ላይ የሌለንን ትልቅ ገንዘብ (ለምሳሌ ትልቅ ዕቃ ለመግዛት) ከባንክ ወይም ከሰው ተውሰን በኋላ ላይ ቀስ እያልን የምንመልሰው ገንዘብ ነው።\n\n- ወለድ (Interest) በብድር ላይ፦ ከባንክ ገንዘብ ስንበደር፣ ባንኩ ገንዘቡን ስላበደረን ብቻ ከዋናው ገንዘብ በተጨማሪ እንድንከፍለው የሚጠይቀን \"የትርፍ\" ወይም የቅጣት ክፍያ ነው።\n\n## 🏦 4. የቁጠባ ሒሳብ (Savings Account) እና የቼክ ሒሳብ (Checking Account)\nባንክ ስንሄድ ሁለት ዓይነት ዋና ዋና የቁጠባ መንገዶች አሉ፦\n\n- የቁጠባ ሒሳብ (Savings)፦ ገንዘባችንን ሳንንካው ለረጅም ጊዜ የምናስቀምጥበት ክፍል ነው። የሚገርመው ነገር፣ ገንዘባችንን እዚያ ስላስቀመጥን ብቻ ባንኩ ለእኛ ተጨማሪ ማበረታቻ ገንዘብ ይከፍለናል፤ ይህ ለአምጪው የሚከፈል ወለድ (Interest) ይባላል!\n\n- የቼክ ሒሳብ (Checking)፦ ወላጆቻችን የእለት ተእለት ወጪዎችን፣ የቤት ኪራይን ወይም የትምህርት ቤት ክፍያዎችን ወዲያውኑ በቼክ ወይም በካርድ ለመክፈል የሚጠቀሙበት ሲሆን፣ ይህ አካውንት ምንም ተጨማሪ ወለድ አያስገኝም።\n\n## 💳 5. ዴቢት ካርድ (Debit) እና ክሬዲት ካርድ (Credit)፦ የፕላስቲክ ሳንቲሞች\nአሁን ላይ ሰዎች በካርድ መግዛት አዘውትረዋል። ነገር ግን ሁለቱ ካርዶች በጣም የተለያዩ ናቸው፦\n\n- ዴቢት ካርድ (Debit Card) — \"የራሴ ገንዘብ\"፦ ይህ ካርድ በቀጥታ ባንክ ውስጥ ካለን የራሳችን ቁጠባ ጋር የተያያዘ ነው። ካርዱን ስንጠቀም ወዲያውኑ የሚቀነሰው በባንክ ካለን የራሳችን ሳንቲም ላይ ብቻ ነው። ካለቀ መግዛት አንችልም።\n\n- ክሬዲት ካርድ (Credit Card) — \"የተዋስኩት ገንዘብ\"፦ ይህ ካርድ ግን ልክ እንደ ትናንሽ ብድር ነው። ካርዱን ስንጠቀም የካርዱ ኩባንያ ለጊዜው ይከፍልልናል፤ እኛ ግን በየወሩ ያጠፋነውን ገንዘብ (አንዳንድ ጊዜ ከነተጨማሪ ወለዱ) ለኩባንያው የመመለስ ግዴታ አለብን።","category":"Financial Literacy","titleAm":"🪙 የገንዘብ ዕውቀት ለልጆች፦ መሠረታዊ የፋይናንስ እና የበጀት አያያዝ መመሪያ","authorId":"t4kdrCrtQxcPqoIFKTRQU3ps7jh1","image":"https://amarachsacco.com/static/blog/needs.png"}]', '[]', '[{"image":"https://amarachsacco.com/static/office.jpg","link":"/service","subtitle":"We combine traditional community values with modern technology to serve you better.","title":"Save Smart, Borrow Better","badge":"24/7 Support","cta":"24/7 Support"},{"badge":"አዳዲስ የዕድል አድማሶችን ለመክፈት አብረውን ይጓዙ።","cta":"የብድር አገልግሎቶችን፣ ከፍተኛ ወለድ የሚያስገኙ የቁጠባ ሂሳቦችን እና ሌሎችንም ጥቅማጥቅሞች ከአማራጭ ሳኮ ያግኙ","subtitle":"Apply for full SACCO membership to access loans, high-interest savings, and more.","title":"Join us as we redefine what''s possible","link":"/blog","image":"data:image/jpeg;base64,"}]', '{"regulatoryImage1":"https://amarachsacco.com/static/lc1.jpeg","storyImage":"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRTJJFwvjQaV55E3cX8bd0vd05HDW-dZglpRg&s","managementTitle":"Management","valuesTitle":"Core Values","regulatoryDescription":"Addis Ababa","regulatoryBadge":"Addis Ababa","licenses":[{"imageUrl":"https://amarachsacco.com/static/lc1.jpeg","issuingOrgan":"Addis Ababa","uniqueNumber":"ET ","subject":"Licensed and regulated by the Addis Ababa City Administration Cooperative Commission"},{"subject":"Issued by-Addis Ababa City Administration Cooperative Commission","uniqueNumber":"001","issuingOrgan":"Federal Cooperative Agency","imageUrl":"https://amarachsacco.com/static/lc2.jpeg"}],"regulatoryTitle":"Licenses","regulatoryImage2":"https://amarachsacco.com/static/lc2.jpeg","storyTitle":"Building Saving Habits Through Digital Excellence","storyDescription":"Amarach Savings and Credit Cooperative (SACCO) was founded in August 2021 with a clear vision: to redefine financial empowerment in Ethiopia. Licensed by the Addis Ababa City Administration Cooperative Commission (Arada Sub-city), Amarach was Established from the collective expertise of a multi-disciplinary team. Our founders bring together specialists from Finance, IT, Law, and Business, creating a unique foundation that blends traditional cooperative values with modern professional excellence."}', '{"whyChooseUsBadge":"eset","whyChooseUsBadge_en":"eset"}', 'To empower our community through innovative financial solutions, fostering a culture of saving and mutual growth through professional excellence and cooperative values.', 'The purpose of Amarach SACCO is to redefine financial empowerment in Ethiopia by blending professional expertise in Finance, IT, and Law with the time-honored principles of the cooperative movement. We exist to foster a culture of consistent saving and provide accessible credit through a secure, tech-driven platform, ensuring our members are equipped to overcome economic challenges. By promoting financial literacy and mutual aid, we aim to build a resilient community where collective growth drives individual success and contributes to the broader development of our nation');

-- Data for table: blog_comments
CREATE TABLE IF NOT EXISTS `blog_comments` (
  `id` VARCHAR(36) PRIMARY KEY,
  `authorPhotoURL` TEXT,
  `createdAt` TIMESTAMP,
  `updatedAt` TIMESTAMP,
  `blogId` TEXT,
  `userId` TEXT,
  `content` TEXT,
  `parentId` TEXT,
  `authorName` TEXT
);
);

